h is essential.WhileanofficialNPDdiagnosisrequiresaclinicalexpert,understandingtoxicrelationshipdynamics empowersindividualstomakehealthierchoices.', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:55+00:00", "source_pdf_sha1": "44394191c8ff", "answer_pdf_sha1": "345fcb11fcba", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "510", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗（作文、英文閱讀與法學知識）", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "土木工程"}'::jsonb, NULL)
